Debounce ensures a function is only called after a pause in repeated invocations for a specified delay.

```javascript
// Simple debounce: delays fn until wait ms have passed since the last call
function debounce(fn, wait = 200) {
  let timeout;
  return function (...args) {
    const context = this;
    clearTimeout(timeout);
    timeout = setTimeout(() => fn.apply(context, args), wait);
  };
}

// Example usage: debounce an input handler
const input = document.querySelector('#search');
function handleSearch(e) {
  console.log('Searching for:', e.target.value);
}
const debouncedSearch = debounce(handleSearch, 300);
input.addEventListener('input', debouncedSearch);

// Or inline for window resize
window.addEventListener('resize', debounce(() => {
  console.log('Window resized — expensive work done after pause');
}, 250));
```
